pub const ComputationError = error{IllegalArgument};

pub fn steps(number: usize) anyerror!usize {
	if (number <= 0) {
		return error.IllegalArgument;
	}

	if (number == 1) {
		return 0;
	}

	return try steps(switch (number % 2) {
		0 => number / 2,
		1 => number * 3 + 1,
		else => unreachable,
	}) + 1;
}
